RuleSet.GenFile:
// Description: C++18 Implementation of a RAM $SchemaName$ loader.

$MssSourceLicense$

#include <cflib/ICFLibPublic.hpp>
#include <$lower SchemaName$/I$SchemaName$Public.hpp>
#include <$lower SchemaName$obj/I$SchemaName$ObjPublic.hpp>
#include <$lower SchemaName$obj/$SchemaName$SchemaObj.hpp>
#include <$lower SchemaName$saxloader/$SchemaName$SaxLoaderPublic.hpp>
#include <$lower SchemaName$ram/$SchemaName$RamSchema.hpp>
#include <$SchemaName$RamLdr.hpp>

static const std::string CLASS_NAME( "$SchemaName$RamLoader" );

int main( int argc, char* argv[] ) {

	if( argc < 1 ) {
		std::cerr << CLASS_NAME + " ERROR: Program name is not available\n";
		return( 1 );
	}
	std::string S_ProcName( argv[0] );
	static const std::string S_System( "system" );
	CFLIB_EXCEPTION_DECLINFO

	cflib::CFLib::init();

	int retval = 0;

	$CPlusNamespace$::I$SchemaName$Schema* $leadlower SchemaName$Schema = NULL;
	$CPlusNamespace$::I$SchemaName$SchemaObj* $leadlower SchemaName$SchemaObj = NULL;
	$CPlusNamespace$::$SchemaName$RamLdr* cli = NULL;
	$CPlusNamespace$::$SchemaName$SaxLoader* loader = NULL;
	$CPlusSecNamespace$::$SecSchemaName$Authorization* auth = NULL;
	std::string* loaderOpts = NULL;
	std::string* url = NULL;
	if( argc >= 3 ) {
		try {
			$leadlower SchemaName$Schema = new $CPlusNamespace$::$SchemaName$RamSchema();
			$leadlower SchemaName$SchemaObj = new $CPlusNamespace$::$SchemaName$SchemaObj();
			$leadlower SchemaName$SchemaObj->setBackingStore( $leadlower SchemaName$Schema );
			cli = new $CPlusNamespace$::$SchemaName$RamLdr();
			loader = cli->getSaxLoader();
			loader->setSchemaObj( $leadlower SchemaName$SchemaObj );
			loaderOpts = new std::string( argv[1] );
			url = new std::string( argv[2] );
			$leadlower SchemaName$Schema->connect( S_System, S_System, S_System, S_System );
			$leadlower SchemaName$Schema->rollback();
			$leadlower SchemaName$Schema->beginTransaction();
			$leadlower SchemaName$SchemaObj->setSecCluster( $leadlower SchemaName$SchemaObj->getClusterTableObj()->getSystemCluster() );
			$leadlower SchemaName$SchemaObj->setSecTenant( $leadlower SchemaName$SchemaObj->getTenantTableObj()->getSystemTenant() );
			$leadlower SchemaName$SchemaObj->setSecSession( $leadlower SchemaName$SchemaObj->getSecSessionTableObj()->getSystemSession() );
			auth = new $CPlusSecNamespace$::$SecSchemaName$Authorization();
			auth->setSecCluster( *($leadlower SchemaName$SchemaObj->getSecCluster()) );
			auth->setSecTenant( *($leadlower SchemaName$SchemaObj->getSecTenant()) );
			auth->setSecSession( $leadlower SchemaName$SchemaObj->getSecSession() );
			$leadlower SchemaName$SchemaObj->setAuthorization( auth );
			cli->applyLoaderOptions( loader, *loaderOpts );
			cli->evaluateRemainingArgs( argc, argv, 3 );
			loader->setUseCluster( $leadlower SchemaName$SchemaObj->getSecCluster() );
			loader->setUseTenant( $leadlower SchemaName$SchemaObj->getSecTenant() );
			loader->parseFile( *url );
			$leadlower SchemaName$Schema->commit();
			$leadlower SchemaName$Schema->disconnect( true );
		}
		CFLIB_EXCEPTION_CATCH_FALLTHROUGH
		if( ! CFLIB_EXCEPTION_EMPTY ) {
			std::cerr << S_ProcName + " SAXParseException : Could not parse XML file \\"" + *url + "\\": " + CFLIB_EXCEPTION_FORMATTEDMESSAGE + "\\n";
		}
		if( ( $leadlower SchemaName$Schema != NULL ) && $leadlower SchemaName$Schema->isConnected() ) {
			try {
				$leadlower SchemaName$Schema->rollback();
			}
			catch ( ... ) {
			}
			try {
				$leadlower SchemaName$Schema->disconnect( false );
			}
			catch( ... ) {
			}
		}
		if( loader != NULL ) {
			loader->setSchemaObj( NULL );
			loader = NULL;
		}
		if( cli != NULL ) {
			delete cli;
			cli = NULL;
		}
		if( $leadlower SchemaName$SchemaObj != NULL ) {
			$leadlower SchemaName$SchemaObj->setBackingStore( NULL );
			try {
				delete $leadlower SchemaName$SchemaObj;
			}
			catch( ... ) {
			}
			$leadlower SchemaName$SchemaObj = NULL;
		}
		if( $leadlower SchemaName$Schema != NULL ) {
			if( $leadlower SchemaName$Schema->isConnected() ) {
				try {
					$leadlower SchemaName$Schema->rollback();
				}
				catch ( ... ) {
				}
				try {
					$leadlower SchemaName$Schema->disconnect( false );
				}
				catch( ... ) {
				}
			}
			try {
				delete $leadlower SchemaName$Schema;
			}
			catch( ... ) {
			}
			$leadlower SchemaName$Schema = NULL;
		}
	}
	else {
		std::cerr << S_ProcName + " ERROR: Expected at least two argument specifying the loader options and the name of the XML file to parse.  The first argument may be empty.\n";
	}

	if( auth != NULL ) {
		delete auth;
		auth = NULL;
	}

	if( url != NULL ) {
		delete url;
		url = NULL;
	}

	if( loaderOpts != NULL ) {
		delete loaderOpts;
		loaderOpts = NULL;
	}

	try {
		cflib::CFLib::release();
	}
	catch( ... ) {
	}

	return( retval );
}
